@require_auth
def api_gateway(path):
    """Main gateway endpoint - forwards authenticated requests to backend."""
    data = request.get_json(silent=True) if request.method in ["POST", "PUT", "PATCH"] else None
    return forward_to_backend(path, method=request.method, data=data)


